for line in sys.stdin:
    line = line.strip()
    if not line:
        continue
    digits = line.replace(' ', '')
    if len(digits) != 16:
        continue
    total = 0
    for i, ch in enumerate(digits):
        d = int(ch)
        if i % 2 == 0:
            # "X" position - double it
            doubled = d * 2
            if doubled >= 10:
                doubled = doubled // 10 + doubled % 10
            total += doubled
        else:
            # "y" position - add as is
            total += d
    if total % 10 == 0:
        print(line)

