import sys

def solve_nqueens(n):
    solutions = []

    def is_safe(queens, row, col):
        for c in range(col):
            r = queens[c]
            if r == row:
                return False
            if abs(r - row) == abs(c - col):
                return False
        return True

    def backtrack(queens, col):
        if col == n:
            solutions.append(''.join(str(q) for q in queens))
            return
        for row in range(1, n + 1):
            if is_safe(queens, row, col):
                queens.append(row)
                backtrack(queens, col + 1)
                queens.pop()

    backtrack([], 0)
    return solutions

for n in range(4, 9):
    solutions = solve_nqueens(n)
    for s in solutions:
        print(s)

